const NAV_ITEMS = [
  { label: "Dashboard", to: "/dashboard", lockUntilSetupVerified: true },
  { label: "Projects", to: "/projects", lockUntilSetupVerified: true },
  { label: "Settings", to: "/settings", lockUntilSetupVerified: false },
];

export default function Sidebar() {
  const isConfigured = useSetupStore((s) => s.isConfigured);

  const locked = isConfigured !== true;

  return (
    <aside className="sticky top-0 hidden h-screen w-72 shrink-0 flex-col overflow-hidden border-r border-slate-800 bg-slate-950/60 px-4 py-6 backdrop-blur md:flex">
      <div className="mb-8 flex items-center gap-3 px-2">
        <div className="grid h-9 w-9 place-items-center rounded-xl bg-white/10 ring-1 ring-white/10">
          <div className="grid grid-cols-2 gap-1">
            <span className="h-1.5 w-1.5 rounded-sm bg-white/70" />
            <span className="h-1.5 w-1.5 rounded-sm bg-white/40" />
            <span className="h-1.5 w-1.5 rounded-sm bg-white/40" />
            <span className="h-1.5 w-1.5 rounded-sm bg-white/70" />
          </div>
        </div>
        <div className="leading-tight">
          <div className="text-base font-semibold tracking-tight">WardenIQ</div>
          {locked ? (
            <div className="mt-0.5 text-xs text-slate-400">
              Complete demo setup to unlock
            </div>
          ) : (
            <div className="mt-0.5 text-xs text-slate-400">Demo ready</div>
          )}
        </div>
      </div>

      <nav className="space-y-2">
        {NAV_ITEMS.map(({ label, to, lockUntilSetupVerified }) => {
          const disabled = locked && lockUntilSetupVerified;

          if (disabled) {
            return (
              <div
                key={to}
                aria-disabled="true"
                title="Complete setup and verify to unlock this section."
                className={[
                  "flex items-center gap-3 rounded-xl px-3 py-2.5 text-sm font-medium",
                  "text-slate-500 opacity-60 cursor-not-allowed select-none",
                  "ring-1 ring-transparent",
                ].join(" ")}
              >
                <Icon className="h-5 w-5 text-white/30" />
                <span className="truncate">{label}</span>
                <span className="ml-auto rounded-lg bg-white/5 px-2 py-0.5 text-[10px] text-slate-400 ring-1 ring-white/10">
                  Locked
                </span>
              </div>
            );
          }

          return (
            <NavLink
              key={to}
              to={to}
              className={({ isActive }) =>
                [
                  "flex items-center gap-3 rounded-xl px-3 py-2.5 text-sm font-medium transition",
                  isActive
                    ? "bg-white/10 text-white ring-1 ring-white/10"
                    : "text-slate-300 hover:bg-white/5 hover:text-white",
                ].join(" ")
              }
            >
              <Icon className="h-5 w-5 text-white/80" />
              <span className="truncate">{label}</span>
            </NavLink>
          );
        })}
      </nav>
    </aside>
  );
};